# Observe the 202 + polling pattern with --debug
az aks create   --resource-group myRG   --name myCluster   --node-count 3   --debug 2>&1 | grep -E "Response status|Azure-AsyncOperation|Location:|Retry-After"

# Key response headers for async operations:
# Azure-AsyncOperation: https://management.azure.com/.../operations/{opId}
# Location: https://management.azure.com/.../operationresults/{opId}
# Retry-After: 30   (seconds to wait before polling)

import requests, time

def arm_put_and_poll(url, body, token, api_version):
    """Submit a PUT request and poll until the LRO completes."""
    headers = {
        "Authorization": f"Bearer {token}",
        "Content-Type": "application/json"
    }

    # Initial PUT
    resp = requests.put(f"{url}?api-version={api_version}", json=body, headers=headers)

    if resp.status_code in (200, 201):
        return resp.json()  # synchronous completion

    if resp.status_code == 202:
        # Asynchronous: poll the operation URL
        poll_url = (
            resp.headers.get("Azure-AsyncOperation") or
            resp.headers.get("Location")
        )
        retry_after = int(resp.headers.get("Retry-After", 30))

        while True:
            time.sleep(retry_after)
            poll_resp = requests.get(poll_url, headers=headers)
            data = poll_resp.json()

            status = data.get("status") or data.get("properties", {}).get("provisioningState")
            print(f"  Status: {status}")

            if status in ("Succeeded", "Canceled", "Failed"):
                if status == "Failed":
                    raise RuntimeError(f"Operation failed: {data.get('error')}")
                return data

    raise RuntimeError(f"Unexpected status: {resp.status_code} {resp.text}")

import requests, time

def arm_request_with_retry(method, url, token, body=None, max_retries=5):
    """Make an ARM request and retry on 429 with exponential backoff."""
    headers = {"Authorization": f"Bearer {token}", "Content-Type": "application/json"}
    delay = 2

    for attempt in range(max_retries):
        if method == "GET":
            resp = requests.get(url, headers=headers)
        else:
            resp = requests.request(method, url, json=body, headers=headers)

        if resp.status_code == 429:
            retry_after = int(resp.headers.get("Retry-After", delay))
            print(f"Rate limited. Waiting {retry_after}s (attempt {attempt + 1}/{max_retries})")
            time.sleep(retry_after)
            delay = min(delay * 2, 64)
            continue

        resp.raise_for_status()
        return resp.json()

    raise RuntimeError(f"Exceeded max retries ({max_retries}) due to rate limiting")

